#include <bits/stdc++.h>
using namespace std;
int x,sum,s[21][2];
bool vis[21];
int i;
void dfs() { //k号选书
	if(i>x) {
		sum++;
		return;
	}//k号选哪一本
	for(int j=0; j<=1; j++) {
		if(vis[s[i++][j]]==0) {
			vis[s[i][j]]=1;
			dfs();
			vis[s[i--][j]]=0;
		}
	}
}
int main() {
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>x;
	for(int i=1; i<=x; i++) {
		cin>>s[i][0]>>s[i][1];
	}
	dfs();
	cout<<sum;
	return 0;
}
